# Verify current answer has all files
import json

with open('/workspace/answer.json', 'r') as f:
    data = json.load(f)

print(f"Total files in answer: {len(data['files'])}")
print("\nFiles by category:")

# Count files by module/category
categories = {}
for file_entry in data['files']:
    path = file_entry['path']
    # Extract first part after clients/connect/server/etc
    if path.startswith('clients'):
        cat = 'clients'
    elif path.startswith('connect'):
        cat = 'connect'
    elif path.startswith('server'):
        cat = 'server'
    elif path.startswith('group-coordinator'):
        cat = 'group-coordinator'
    elif path.startswith('share-coordinator'):
        cat = 'share-coordinator'
    elif path.startswith('transaction-coordinator'):
        cat = 'transaction-coordinator'
    elif path.startswith('raft'):
        cat = 'raft'
    elif path.startswith('metadata'):
        cat = 'metadata'
    elif path.startswith('storage'):
        cat = 'storage'
    elif path.startswith('tools'):
        cat = 'tools'
    elif path.startswith('server-common'):
        cat = 'server-common'
    else:
        cat = 'other'

    categories[cat] = categories.get(cat, 0) + 1

for cat in sorted(categories.keys()):
    print(f"  {cat}: {categories[cat]}")
EOF

